import olympiad;
unitsize (0.5 cm);

pair O, P, Q, V;

O = (0,0);
P = (5,0);
V = (5,8);
Q = (P + reflect(O,V)*(P))/2;

draw(O--P--V--cycle);
draw(P--Q);
draw(rightanglemark(O,P,V,14));
draw(rightanglemark(P,Q,O,14));

label("$O$", O, SW);
label("$P$", P, SE);
label("$Q$", Q, NW);
label("$V$", V, NE);
[/asy]

